        const int MOD = 1e9 + 7;
        vector<long long> dp(x + 1, 1);
        for (int i = 1; i <= n; ++i) {
            vector<long long> ndp(x + 1, 0);
            for (int j = 1; j <= x; ++j) {
                for (int k = 1; k <= j; ++k) {
                    ndp[j] = (ndp[j] + dp[k] * powmod(y, i - 1)) % MOD;
                }
            }
            dp = ndp;
        }
        long long res = 0;
        for (int i = 1; i <= x; ++i) {
            res = (res + dp[i] * powmod(y, n)) % MOD;
        }
        return res;
    }
    long long powmod(long long a, long long b) {
        long long res = 1;
        while (b) {
            if (b & 1) res = res * a % MOD;
            a = a * a % MOD;
            b >>= 1;
        }
        return res;
    }
};
